const { Manifold, CrossSection } = api;

// 1. Core walls of the estate
const mainWall = Manifold.cube([50, 20, 25], true).translate([0, 0, 12.5]);
const leftWingWall = Manifold.cube([15, 23, 25], true).translate([-32.5, -1.5, 12.5]);
const rightWingWall = Manifold.cube([15, 23, 25], true).translate([32.5, -1.5, 12.5]);
const walls = mainWall.add(leftWingWall).add(rightWingWall);

// Helper for architectural window construction
function createWindow(w, h, depth) {
  const frameOuter = Manifold.cube([w, depth, h], true);
  const frameInner = Manifold.cube([w - 0.8, depth + 0.2, h - 0.8], true);
  const frame = frameOuter.subtract(frameInner);

  const glass = Manifold.cube([w - 0.7, depth - 0.1, h - 0.7], true);

  // High-detail sash window mullions (grids)
  const vertMullion = Manifold.cube([0.2, depth - 0.05, h - 0.8], true);
  const horizMullion1 = Manifold.cube([w - 0.8, depth - 0.05, 0.2], true).translate([0, 0, h / 6]);
  const horizMullion2 = Manifold.cube([w - 0.8, depth - 0.05, 0.2], true).translate([0, 0, -h / 6]);

  return {
    frame: frame,
    glass: glass.add(vertMullion).add(horizMullion1).add(horizMullion2)
  };
}

function makeWindowInstance(w, h, depth, pos, orientation) {
  const win = createWindow(w, h, depth);
  let frame = win.frame;
  let glass = win.glass;
  if (orientation === 'left') {
    frame = frame.rotate([0, 0, 90]);
    glass = glass.rotate([0, 0, 90]);
  } else if (orientation === 'right') {
    frame = frame.rotate([0, 0, -90]);
    glass = glass.rotate([0, 0, -90]);
  }
  return {
    frame: frame.translate(pos),
    glass: glass.translate(pos)
  };
}

const windowFrames = [];
const windowGlasses = [];

function addWin(x, y, z, w, h, orient) {
  const win = makeWindowInstance(w, h, 1, [x, y, z], orient);
  windowFrames.push(win.frame);
  windowGlasses.push(win.glass);
}

// Front-facing window grid coordinates (perfectly matching Belton House rhythm)
const frontCols = [
  { x: -36, y: -13, wing: true },
  { x: -29, y: -13, wing: true },
  { x: -21, y: -10, wing: false },
  { x: -14, y: -10, wing: false },
  { x: -7, y: -10, wing: false },
  { x: 0, y: -10, wing: false, center: true },
  { x: 7, y: -10, wing: false },
  { x: 14, y: -10, wing: false },
  { x: 21, y: -10, wing: false },
  { x: 29, y: -13, wing: true },
  { x: 36, y: -13, wing: true }
];

frontCols.forEach(col => {
  if (col.center) {
    // Center column houses the main door at ground floor, with window above
    addWin(col.x, col.y, 20, 3.5, 6, 'front');
  } else {
    addWin(col.x, col.y, 1.8, 3.5, 2, 'front'); // Basement window
    addWin(col.x, col.y, 9.5, 3.5, 8, 'front'); // Grand piano nobile window
    addWin(col.x, col.y, 20, 3.5, 6, 'front'); // Upper floor window
  }
});

// Side window columns on projecting wings
const sideColsY = [-6, 4];
sideColsY.forEach(y => {
  // Left Wing West-facing side
  addWin(-40, y, 1.8, 3.5, 2, 'left');
  addWin(-40, y, 9.5, 3.5, 8, 'left');
  addWin(-40, y, 20, 3.5, 6, 'left');
  // Right Wing East-facing side
  addWin(40, y, 1.8, 3.5, 2, 'right');
  addWin(40, y, 9.5, 3.5, 8, 'right');
  addWin(40, y, 20, 3.5, 6, 'right');
});

// Front entrance portico & door
const door = Manifold.cube([4, 1.2, 8], true).translate([0, -10, 8]);
const colL = Manifold.cylinder(8, 0.5, 0.5).translate([-3.5, -11, 4]);
const colR = Manifold.cylinder(8, 0.5, 0.5).translate([3.5, -11, 4]);
const slab = Manifold.cube([9, 2, 1], true).translate([0, -11, 12.5]);
const doorPedProfile = CrossSection.ofPolygons([
  [
    [-4.5, 0],
    [4.5, 0],
    [0, 2]
  ]
]);
const doorPed = doorPedProfile.extrude(2).rotate([90, 0, 0]).translate([0, -10, 13]);

// Central grand pediment & ornamental coat of arms/crest
const pedimentProfile = CrossSection.ofPolygons([
  [
    [-11, 0],
    [11, 0],
    [0, 4.5]
  ]
]);
const pediment = pedimentProfile.extrude(2.5).rotate([90, 0, 0]).translate([0, -10, 25]);
const crest = Manifold.sphere(1.5).scale([1, 0.5, 1.3]).translate([0, -11, 26.5]);

// Classical hip roofs (created as perfect convex hulls of bottom & top flat sections)
const boxBottomL = Manifold.cube([15, 23, 0.1], true).translate([-32.5, -1.5, 25]);
const boxTopL = Manifold.cube([11, 19, 0.1], true).translate([-32.5, -1.5, 32]);
const roofL = boxBottomL.add(boxTopL).hull();

const boxBottomR = Manifold.cube([15, 23, 0.1], true).translate([32.5, -1.5, 25]);
const boxTopR = Manifold.cube([11, 19, 0.1], true).translate([32.5, -1.5, 32]);
const roofR = boxBottomR.add(boxTopR).hull();

const boxBottomC = Manifold.cube([50.2, 20.2, 0.1], true).translate([0, 0, 25]);
const boxTopC = Manifold.cube([46, 16, 0.1], true).translate([0, 0, 32]);
const roofC = boxBottomC.add(boxTopC).hull();

// Rooftop balustrade helper
function createBalustrade(xMin, xMax, yMin, yMax, zMin, zMax) {
  const outer = Manifold.cube([xMax - xMin, yMax - yMin, zMax - zMin], true);
  const inner = Manifold.cube([xMax - xMin - 0.6, yMax - yMin - 0.6, zMax - zMin + 0.2], true);
  return outer.subtract(inner).translate([(xMin + xMax) / 2, (yMin + yMax) / 2, (zMin + zMax) / 2]);
}

// Dormer windows on roof slopes
function createDormer(cx, cy, cz) {
  const body = Manifold.cube([3, 4, 3], true).translate([0, 0, 1.5]);
  const roofProfile = CrossSection.ofPolygons([
    [
      [-1.6, 0],
      [1.6, 0],
      [0, 1.2]
    ]
  ]);
  const roof = roofProfile.extrude(4.2).rotate([90, 0, 0]).translate([0, 2.1, 3]);
  const windowFrame = Manifold.cube([1.8, 0.5, 1.8], true).translate([0, -2.05, 1.5]);
  const windowGlass = Manifold.cube([1.4, 0.4, 1.4], true).translate([0, -2.1, 1.5]);
  return {
    stone: body.translate([cx, cy, cz]),
    roof: roof.translate([cx, cy, cz]),
    frame: windowFrame.translate([cx, cy, cz]),
    glass: windowGlass.translate([cx, cy, cz])
  };
}

const dormerStone = [];
const dormerRoofs = [];
const dormerFrames = [];
const dormerGlasses = [];

const dormerPositions = [
  { x: -32.5, y: -11.5, z: 27 }, // Wing L front
  { x: 32.5, y: -11.5, z: 27 }, // Wing R front
  { x: -21, y: -8.5, z: 27 }, // Recessed center L
  { x: -14, y: -8.5, z: 27 }, // Recessed center L-mid
  { x: 14, y: -8.5, z: 27 }, // Recessed center R-mid
  { x: 21, y: -8.5, z: 27 } // Recessed center R
];

dormerPositions.forEach(pos => {
  const d = createDormer(pos.x, pos.y, pos.z);
  dormerStone.push(d.stone);
  dormerRoofs.push(d.roof);
  dormerFrames.push(d.frame);
  dormerGlasses.push(d.glass);
});

// Chimneys & Clay pots
function createChimney(cx, cy) {
  const block = Manifold.cube([4, 4, 7], true).translate([cx, cy, 34.5]);
  const pot1 = Manifold.cylinder(1.5, 0.4, 0.35).translate([cx - 1.2, cy, 38]);
  const pot2 = Manifold.cylinder(1.5, 0.4, 0.35).translate([cx, cy, 38]);
  const pot3 = Manifold.cylinder(1.5, 0.4, 0.35).translate([cx + 1.2, cy, 38]);
  return { block, pots: pot1.add(pot2).add(pot3) };
}

const chimneyBlocks = [];
const chimneyPots = [];

const chimneyPositions = [
  { x: -32.5, y: -2 },
  { x: -32.5, y: 6 },
  { x: 32.5, y: -2 },
  { x: 32.5, y: 6 },
  { x: -18, y: 4 },
  { x: 18, y: 4 }
];

chimneyPositions.forEach(pos => {
  const chim = createChimney(pos.x, pos.y);
  chimneyBlocks.push(chim.block);
  chimneyPots.push(chim.pots);
});

// Central roof lantern/cupola
const cupolaBase = Manifold.cylinder(1.5, 4.5, 4.5, 8).translate([0, 0, 32]);
const col = Manifold.cylinder(4, 0.35, 0.35).translate([3.3, 0, 33.5]);
const cupolaCols = api.circularPattern(col, 8);
const cupolaGlass = Manifold.cylinder(4, 3.1, 3.1, 8).translate([0, 0, 33.5]);
const domeBase = Manifold.cylinder(1, 3.8, 3.8, 8).translate([0, 0, 37.5]);
const dome = Manifold.sphere(3.8).scale([1, 1, 0.8]).translate([0, 0, 38.5]);
const spindle = Manifold.cylinder(3.5, 0.15, 0.15).translate([0, 0, 41]);

// Grand entrance stairs and heavy stone balustrades
let steps = Manifold.cube([28, 0.1, 0.1], true);
const stepCount = 12;
const stepHeight = 4 / stepCount;
const stepWidth = 28;
for (let i = 1; i <= stepCount; i++) {
  const h = i * stepHeight;
  const d = (stepCount - i + 1) * 0.6;
  const stepBox = Manifold.cube([stepWidth, d, h], true).translate([0, -10 - d / 2, h / 2]);
  steps = steps.add(stepBox);
}

const leftPillarFront = Manifold.cube([1, 1, 1.5], true).translate([-14.5, -17, 0.75]);
const leftPillarBack = Manifold.cube([1, 1, 5.5], true).translate([-14.5, -10, 2.75]);
const leftBalustrade = leftPillarFront.add(leftPillarBack).hull();

const rightPillarFront = Manifold.cube([1, 1, 1.5], true).translate([14.5, -17, 0.75]);
const rightPillarBack = Manifold.cube([1, 1, 5.5], true).translate([14.5, -10, 2.75]);
const rightBalustrade = rightPillarFront.add(rightPillarBack).hull();

// Group geometry and apply self-coloring labels for beautiful multi-color prints
const facadeShape = walls
  .add(colL).add(colR).add(slab).add(doorPed)
  .add(pediment)
  .add(crest)
  .add(Manifold.union(dormerStone))
  .add(cupolaBase)
  .add(cupolaCols)
  .add(domeBase)
  .add(Manifold.union(chimneyBlocks))
  .add(leftBalustrade)
  .add(rightBalustrade);

const roofShape = roofL
  .add(roofR)
  .add(roofC)
  .add(Manifold.union(dormerRoofs))
  .add(createBalustrade(-23, 23, -8, 8, 32, 33.5))
  .add(createBalustrade(-38, -27, -11, 8, 32, 33.5))
  .add(createBalustrade(27, 38, -11, 8, 32, 33.5));

const frameShape = Manifold.union(windowFrames).add(Manifold.union(dormerFrames));
const glassShape = Manifold.union(windowGlasses).add(Manifold.union(dormerGlasses)).add(cupolaGlass);
const cupolaDomeShape = dome.add(spindle);
const chimneyPotsShape = Manifold.union(chimneyPots);
const stepsShape = steps;
const doorShape = door;

return api.labeledUnion([
  { name: 'facade', shape: facadeShape, color: '#dfcca9' }, // Warm buff limestone
  { name: 'roof', shape: roofShape, color: '#4f5d73' }, // Blue slate tile
  { name: 'window_frames', shape: frameShape, color: '#ffffff' }, // Classic white sash frames
  { name: 'window_glass', shape: glassShape, color: '#1c2833' }, // Pane reflections
  { name: 'cupola_dome', shape: cupolaDomeShape, color: '#708090' }, // Lead sheeting
  { name: 'chimney_pots', shape: chimneyPotsShape, color: '#c05c3e' }, // Clay pots
  { name: 'steps', shape: stepsShape, color: '#8c92ac' }, // Granite grey steps
  { name: 'door', shape: doorShape, color: '#2c1a04' } // Dark oak door
]);
